def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    def estimate_arrival_time(dist, speed):
        return current_time + dist / speed

    def time_in_window(arrival, window):
        if arrival < window[0]:
            return (window[0] - arrival) ** 2
        elif arrival > window[1]:
            return (arrival - window[1]) ** 2
        return 0

    def assign_completion_priority(distances, starts):
        return sorted(range(len(starts)), key=lambda i: distances[i] / max(1, (starts[i] - current_time)))

    distances = [calculate_distance(cur_truck_pos, customer) for customer in unvisited_customers]
    time_estimates = [estimate_arrival_time(dist, truck_speed) for dist in distances]
    time_penalties = [time_in_window(time_estimates[i], time_windows[i]) for i in range(len(unvisited_customers))]

    if current_time == 0:
        start_times = [time[0] for time in time_windows]
        return assign_completion_priority(distances, start_times)[0]

    min_penalty = min(time_penalties)
    for i, penalty in enumerate(time_penalties):
        if penalty == min_penalty:
            return i

    return best_node

