        return np.linalg.norm(p1 - p2)

    def adaptability_score(customer_positions, current_time, tws, depot):
        urgency_scores = []
        for i, (customer, tw) in enumerate(zip(customer_positions, tws)):
            dist_to_depot = calculate_distance(customer, depot)
            time_left = max(0, tw[1] - current_time)  # Time remaining to end of window
            urgency = 1 / (time_left + 1)  # More urgent as time_left decreases
            depot_factor = 1 / (1 + dist_to_depot)  # Higher score if closer to depot
            urgency_scores.append(urgency + depot_factor)
        return np.array(urgency_scores)

    customers_scores = adaptability_score(np.array(unvisited_customers), current_time, time_windows, depot_pos)

    best_node = None
    best_score = float('inf')

    for i, customer in enumerate(unvisited_customers):
        dist_to_customer = calculate_distance(cur_truck_pos, customer)
        travel_cost = dist_to_customer / truck_speed
        arrival_time = current_time + travel_cost

        time_window = time_windows[i]
        if arrival_time < time_window[0]:
            wait_cost = time_window[0] - arrival_time
        elif arrival_time > time_window[1]:
            wait_cost = (arrival_time - time_window[1]) * 10  # Enhance penalty for missing window
        else:
            wait_cost = 0

        total_score = travel_cost + wait_cost - customers_scores[i]  # Minus score because higher adaptability means lower total score

